const input = $input.first().json;
const level = input.level || 'INFO';
const title = input.title || 'AiBrand 系统通知';
const message = input.message || '';
const taskId = input.task_id || 'N/A';

// 按级别选择通知渠道
let channels = ['log'];
if (level === 'CRITICAL' || level === 'ERROR') {
  channels = ['wecom', 'feishu', 'log'];
} else if (level === 'WARN') {
  channels = ['wecom', 'log'];
} else {
  channels = ['log'];
}

const emoji = { 'CRITICAL': '🔴', 'ERROR': '❌', 'WARN': '⚠️', 'INFO': 'ℹ️', 'SUCCESS': '✅' };

return {
  level: level,
  title: title,
  message: `${emoji[level] || ''} **${title}**\n> ${message}\n\n📋 Task: ${taskId}\n🕐 Time: ${new Date().toISOString()}`,
  channels: channels,
  task_id: taskId,
  timestamp: new Date().toISOString()
};

const result = $input.first().json;
const notification = $('Build Notification').first().json;

return {
  sent: true,
  level: notification.level,
  channels: notification.channels,
  message: notification.message,
  openclaw_response: result,
  timestamp: notification.timestamp
};
